  function renderExploreCard(item,index,full){var meta=imageSizeMeta(item.size||'1024x1024');var tags=Array.isArray(item.tags)?item.tags:[];return '<button class="image-explore-card'+(full?' explore-page-card':'')+'" data-action="select-explore-image" data-explore-id="'+escapeHtml(item.id)+'" data-explore-image="'+escapeHtml(item.imageUrl)+'" data-explore-size="'+escapeHtml(item.size||'1024x1024')+'" data-explore-tags="'+escapeHtml(tags.join(' '))+'" style="--explore-index:'+String(index)+';aspect-ratio:'+String(meta.width)+' / '+String(meta.height)+'" type="button" aria-label="Use this image as a visual reference"><img src="'+escapeHtml(item.imageUrl)+'" alt="" loading="'+(full?'eager':'lazy')+'"/><span class="explore-generate-mark" aria-hidden="true"><svg width="16" height="16" viewBox="0 0 24 24" fill="none"><path d="M12 3.8v4.4M12 15.8v4.4M4.8 12h4.4M14.8 12h4.4M7.1 7.1l3.1 3.1M13.8 13.8l3.1 3.1M16.9 7.1l-3.1 3.1M10.2 13.8l-3.1 3.1" stroke="currentColor" stroke-width="1.75" stroke-linecap="round"/><circle cx="12" cy="12" r="2.35" fill="currentColor"/></svg></span></button>'}
  function currentExploreItems(){return allExploreItems.filter(function(item){return item&&item.imageUrl&&String(item.size||'1024x1024')==='1152x1536'}).slice(0,10)}
  function renderImageExplore(items){if(Array.isArray(items))allExploreItems=items.filter(function(item){return item&&item.imageUrl});var section=q('imageExplore');var grid=q('imageExploreGrid');var visible=currentExploreItems();if(section){section.classList.toggle('show',visible.length>0);section.setAttribute('aria-hidden',visible.length?'false':'true')}setText('imageExploreCount',String(visible.length)+' cards');if(grid)grid.innerHTML=visible.map(function(item,index){return renderExploreCard(item,index,false)}).join('');renderExplorePage()}
  function exploreSearchText(item){return String((item&&item.id)||'')+' '+String((item&&item.size)||'')+' '+(Array.isArray(item&&item.tags)?item.tags.join(' '):'')}
  function filteredExploreItems(){var query=exploreSearchQuery.trim().toLowerCase();return allExploreItems.filter(function(item){return item&&item.imageUrl&&(!query||exploreSearchText(item).toLowerCase().indexOf(query)>=0)})}
  function renderExplorePage(){var grid=q('explorePageGrid');var items=filteredExploreItems();setText('explorePageCount',String(items.length)+' cards');var empty=q('exploreEmpty');if(empty){empty.classList.toggle('show',!items.length);empty.setAttribute('aria-hidden',items.length?'true':'false')}if(!grid)return;grid.classList.remove('searching');void grid.offsetWidth;grid.classList.add('searching');var columns=[[],[],[]],heights=[0,0,0];items.forEach(function(item,index){var meta=imageSizeMeta(item.size||'1024x1024');var target=heights.indexOf(Math.min.apply(Math,heights));columns[target].push(renderExploreCard(item,index,true));heights[target]+=meta.height/meta.width+.08});grid.innerHTML=columns.map(function(cards){return '<div class="explore-page-column">'+cards.join('')+'</div>'}).join('')}
  function setExplorePage(open){if(open)trackSectionOpen('explore');var page=q('explorePage');if(!page)return;page.classList.toggle('show',!!open);page.setAttribute('aria-hidden',open?'false':'true');document.body.classList.toggle('explore-page-open',!!open);if(tg&&tg.BackButton){try{if(open){tg.BackButton.show();tg.BackButton.onClick(closeExplorePage)}else{tg.BackButton.offClick&&tg.BackButton.offClick(closeExplorePage);tg.BackButton.hide()}}catch(e){}}}
