  function animateExploreToChip(image,chip){if(!image||!chip)return;var reduced=window.matchMedia&&window.matchMedia('(prefers-reduced-motion: reduce)').matches;if(reduced||!image.animate){chip.classList.add('show','arrived');return}var from=image.getBoundingClientRect();chip.classList.add('show');var to=chip.getBoundingClientRect();var flyer=image.cloneNode();flyer.className='explore-reference-fly';flyer.style.cssText='left:'+from.left+'px;top:'+from.top+'px;width:'+from.width+'px;height:'+from.height+'px';document.body.appendChild(flyer);var animation=flyer.animate([{transform:'translate3d(0,0,0) scale(1)',borderRadius:'20px',opacity:1},{transform:'translate3d('+(to.left-from.left)+'px,'+(to.top-from.top)+'px,0) scale('+(to.width/from.width)+')',borderRadius:'9px',opacity:.9}],{duration:520,easing:'cubic-bezier(.16,.86,.22,1)',fill:'forwards'});animation.onfinish=function(){flyer.remove();chip.classList.add('arrived');setTimeout(function(){chip.classList.remove('arrived')},420)};animation.oncancel=function(){flyer.remove()}}
  function clearExploreImage(){var input=q('imagePrompt');selectedExplore=null;document.querySelectorAll('.image-explore-card').forEach(function(item){item.classList.remove('active')});var chip=q('exploreReferenceChip');if(chip){chip.classList.remove('show','arrived');chip.setAttribute('aria-hidden','true')}var composer=document.querySelector('.image-composer');if(composer)composer.classList.remove('explore-selected');if(input){input.readOnly=false;input.style.pointerEvents='';input.dir='auto';input.value=imagePromptBeforeExplore;input.placeholder='Describe the image you want to create';input.removeAttribute('aria-label');updateImagePromptCount()}}
  function selectExploreImage(button){var id=button.getAttribute('data-explore-id')||'';var image=button.querySelector('img');if(!id||!image)return;if(selectedExplore&&selectedExplore.id===id){clearExploreImage();return}var input=q('imagePrompt');if(!selectedExplore&&input)imagePromptBeforeExplore=input.value||'';selectedExplore={id:id,imageUrl:button.getAttribute('data-explore-image')||image.src};document.querySelectorAll('.image-explore-card').forEach(function(item){item.classList.toggle('active',item===button)});var thumb=q('exploreReferenceThumb');var chip=q('exploreReferenceChip');if(thumb)thumb.src=selectedExplore.imageUrl;if(chip)chip.setAttribute('aria-hidden','false');var composer=document.querySelector('.image-composer');if(composer)composer.classList.add('explore-selected');if(input){input.value='';input.dir=['fa','ar'].indexOf(normalizedLanguage())>=0?'rtl':'ltr';input.placeholder=exploreCopy();input.setAttribute('aria-label',exploreCopy());input.readOnly=true;input.style.pointerEvents='none';updateImagePromptCount()}dismissKeyboard();animateExploreToChip(image,chip)}

  async function showGeneratedImage(data,prompt){var result=q('imageResult');var archivedId='';if(currentImageRecord&&result&&result.classList.contains('show')){archivedId=currentImageRecord.id;result.classList.add('archiving');await new Promise(function(resolve){setTimeout(resolve,280)});currentImageRecord=null;result.classList.remove('show','archiving');result.setAttribute('aria-hidden','true')}var size=String(data.size||selectedImageSize);var mimeType=String(data.mimeType||'image/jpeg');var record={id:String(Date.now())+'-'+Math.random().toString(36).slice(2,8),src:'data:'+mimeType+';base64,'+data.imageBase64,filename:String(data.filename||'vexa-image.jpg'),prompt:prompt,size:size,historyId:data.historyId?String(data.historyId):'',createdAt:Date.now()};currentImageRecord=record;generatedImageSrc=record.src;generatedImageName=record.filename;var preview=q('imageResultPreview');if(preview)preview.src=record.src;if(result){applyImageResultSize(result,size);void result.offsetWidth;result.classList.add('show','revealing');result.setAttribute('aria-hidden','false');setTimeout(function(){result.classList.remove('revealing');result.scrollIntoView({behavior:'smooth',block:'end'})},100)}await saveImageRecord(record,archivedId)}
  async function generateMiniAppImage(){var prompt=(q('imagePrompt')&&q('imagePrompt').value.trim())||'';if(selectedExplore&&!sourceImages.length)return toast(exploreCopy());if(!selectedExplore&&!prompt)return toast('Describe the image you want first');var imageCost=Number(imagePricing.activeCost)||188;if(availableCredits!==null&&availableCredits<imageCost)return toast('Not enough credits · Image creation costs '+imageCost+' credits');dismissKeyboard();var button=q('generateImageButton');if(button){button.disabled=true;button.classList.add('loading')}try{var data=await api('/mini-app/api/image',{prompt:prompt,exploreId:selectedExplore?selectedExplore.id:'',images:sourceImages.map(function(item){return{data:item.data,name:item.name}}),size:selectedImageSize});availableCredits=Math.max(0,Number(data.balance)||0);if(data.pricing)updateImagePricing(data.pricing);setText('balance',availableCredits.toLocaleString('en-US'));await showGeneratedImage(data,prompt||exploreCopy())}catch(error){toast(error.message||'Could not create image')}finally{if(button){button.disabled=false;button.classList.remove('loading')}}}
  function imageSourceToBlob(src){var match=String(src||'').match(/^data:([^;]+);base64,(.+)$/);if(!match)throw new Error('Image data is unavailable');var binary=atob(match[2]);var bytes=new Uint8Array(binary.length);for(var index=0;index<binary.length;index+=1)bytes[index]=binary.charCodeAt(index);return new Blob([bytes],{type:match[1]||'image/jpeg'})}
