  function generatedImageFile(){var blob=imageSourceToBlob(generatedImageSrc);return new File([blob],generatedImageName||'vexa-image.jpg',{type:blob.type||'image/jpeg'})}
  async function shareGeneratedImage(){if(!generatedImageSrc)return toast('Create an image first');try{var file=generatedImageFile();if(navigator.share&&(!navigator.canShare||navigator.canShare({files:[file]}))){await navigator.share({files:[file],title:'Vexa'});return}saveBlobWithLink(file,generatedImageName)}catch(error){if(error&&error.name!=='AbortError')toast('Could not share image')}}
